  "components/HookDemoCard.tsx": "import type { ReactNode } from 'react';\n\nexport function HookDemoCard({\n  module,\n  name,\n  hint,\n  children,\n}: {\n  module: '@ha' | '@ha/ui' | '@ha/layout' | '@ha/format';\n  name: string;\n  hint?: string;\n  children: ReactNode;\n}) {\n  return (\n    <article className=\"rd-card rd-dd-hook\">\n      <header className=\"rd-dd-hook__head\">\n        <span className=\"rd-dd-hook__module\">{module}</span>\n        <code className=\"rd-dd-hook__name\">{name}</code>\n        {hint && <p className=\"rd-dd-hook__hint\">{hint}</p>}\n      </header>\n      <div className=\"rd-dd-hook__live\">{children}</div>\n    </article>\n  );\n}\n",
  "components/PageHead.tsx": "import type { ReactNode } from 'react';\n\n/** Page header for example-dashboard reference tabs. */\nexport function PageHead({\n  icon,\n  module,\n  title,\n  children,\n}: {\n  icon: string;\n  module: string;\n  title: string;\n  children: ReactNode;\n}) {\n  return (\n    <header className=\"rd-pagehead rd-glass\">\n      <span className=\"rd-pagehead__icon\" aria-hidden>{icon}</span>\n      <div className=\"rd-pagehead__text\">\n        <span className=\"rd-pagehead__module\">{module}</span>\n        <h2>{title}</h2>\n        <p>{children}</p>\n      </div>\n    </header>\n  );\n}\n",
